	cmp         w8,w9
	bls         |$LN5@IPv4Calcul|

; 52   : 			sum = (sum >> 16) + (sum & 0xFFFF);

	ldr         w8,[sp]
	lsr         w9,w8,#0x10
	ldr         w8,[sp]
	and         w8,w8,#0xFFFF
	add         w8,w9,w8
	str         w8,[sp]
|$LN5@IPv4Calcul|

; 53   : 		}
; 54   : 	}

	b           |$LN2@IPv4Calcul|
|$LN3@IPv4Calcul|

; 55   : 	return ~(sum & 0xFFFF) & 0xFFFF;

	ldr         w8,[sp]
	and         w8,w8,#0xFFFF
	mvn         w8,w8
	and         w8,w8,#0xFFFF
	uxth        w0,w8
	mov         w0,w0
	add         sp,sp,#0x20
	ret

	ENDP  ; |IPv4CalculateChecksum|

	END
